import React from 'react';
import { Link } from 'react-router-dom';

function Services() {
  const serviceData = [
    { id: 1, title: "Web Development", icon: "fas fa-laptop-code", desc: "Crafting high-speed, futuristic websites that convert visitors into customers.", color: "#0d6efd" },
    { id: 2, title: "UI/UX Design", icon: "fas fa-bezier-curve", desc: "Pixel-perfect designs focused on user psychology and modern aesthetics.", color: "#dc3545" },
    { id: 3, title: "App Development", icon: "fas fa-mobile-alt", desc: "Powerful native and cross-platform apps with seamless user experiences.", color: "#198754" },
    { id: 4, title: "Assignment Support", icon: "fas fa-user-graduate", desc: "Expert academic guidance to help you score the highest in your finals.", color: "#ffc107" },
    { id: 5, title: "PPT Design", icon: "fas fa-layer-group", desc: "High-impact visual storytelling that makes your presentations unforgettable.", color: "#0dcaf0" },
    { id: 6, title: "Report Writing", icon: "fas fa-file-contract", desc: "Professional, data-driven technical reports and business documentation.", color: "#6c757d" },
    { id: 7, title: "Digital Marketing", icon: "fas fa-chart-line", desc: "Dominate the market with ROI-focused digital growth strategies.", color: "#343a40" },
    { id: 8, title: "Content Writing", icon: "fas fa-pen-fancy", desc: "Compelling copy that speaks your brand's voice and engages readers.", color: "#0d6efd" },
    { id: 9, title: "SEO Optimization", icon: "fas fa-search-dollar", desc: "Be on the first page. We optimize your visibility for maximum reach.", color: "#0dcaf0" }
  ];

  return (
    <div className="premium-services py-5">
      <div className="container">
        {/* Animated Header Section */}
        <div className="text-center mb-5 overflow-hidden">
          <h1 className="main-title fw-black animate-text">UNMATCHED EXPERTISE</h1>
          <p className="sub-title text-muted">Innovative Solutions Tailored for Visionaries</p>
          <div className="animated-bar mx-auto"></div>
        </div>

        <div className="row g-4 pt-4">
          {serviceData.map((service) => (
            <div className="col-lg-4 col-md-6" key={service.id}>
              <div className="ultra-card shadow-lg h-100">
                <div className="card-inner">
                  {/* Decorative Glow */}
                  <div className="glow-effect" style={{ '--glow-color': service.color }}></div>
                  
                  <div className="top-section">
                    <div className="icon-badge" style={{ backgroundColor: service.color }}>
                      <i className={service.icon}></i>
                    </div>
                    <span className="service-id">0{service.id}</span>
                  </div>

                  <div className="card-body-content">
                    <h3 className="service-title">{service.title}</h3>
                    <p className="service-desc">{service.desc}</p>
                    
                    <Link to="/register" className="premium-btn">
                      <span>Get Started</span>
                      <div className="btn-icon"><i className="fas fa-arrow-right"></i></div>
                    </Link>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* --- PURE PREMIUM CSS (The Magic) --- */}
      <style>{`
        @import url('https://fonts.googleapis.com');

        .premium-services {
          background-color: #ffffff;
          font-family: 'Outfit', sans-serif;
          overflow: hidden;
        }

        .main-title {
          font-size: 3.5rem;
          font-weight: 900;
          letter-spacing: -2px;
          color: #1a1a1a;
          margin-bottom: 0;
        }

        .animated-bar {
          width: 80px;
          height: 6px;
          background: #0d6efd;
          border-radius: 10px;
          position: relative;
          animation: slide 2s infinite ease-in-out;
        }

        @keyframes slide {
          0% { transform: scaleX(1); }
          50% { transform: scaleX(2); }
          100% { transform: scaleX(1); }
        }

        .ultra-card {
          position: relative;
          background: #ffffff;
          border-radius: 30px;
          border: 1px solid #f0f0f0;
          transition: all 0.5s cubic-bezier(0.165, 0.84, 0.44, 1);
          overflow: hidden;
          z-index: 1;
        }

        .card-inner {
          padding: 40px;
          position: relative;
          z-index: 2;
        }

        .ultra-card:hover {
          transform: translateY(-15px) scale(1.02);
          border-color: transparent;
        }

        .glow-effect {
          position: absolute;
          top: 0; left: 0; width: 100%; height: 100%;
          background: radial-gradient(circle at top right, var(--glow-color), transparent 70%);
          opacity: 0;
          transition: opacity 0.5s ease;
          z-index: -1;
        }

        .ultra-card:hover .glow-effect {
          opacity: 0.08;
        }

        .icon-badge {
          width: 60px;
          height: 60px;
          border-radius: 18px;
          display: flex;
          align-items: center;
          justify-content: center;
          color: white;
          font-size: 1.5rem;
          box-shadow: 0 10px 20px rgba(0,0,0,0.1);
          margin-bottom: 25px;
        }

        .service-id {
          position: absolute;
          top: 30px;
          right: 35px;
          font-size: 3rem;
          font-weight: 900;
          color: #f5f5f5;
          z-index: -1;
          transition: 0.5s;
        }

        .ultra-card:hover .service-id {
          color: #eef2ff;
          transform: translateY(-5px);
        }

        .service-title {
          font-weight: 700;
          font-size: 1.5rem;
          color: #1a1a1a;
          margin-bottom: 15px;
        }

        .service-desc {
          color: #666;
          font-size: 0.95rem;
          line-height: 1.6;
          margin-bottom: 30px;
        }

        .premium-btn {
          display: flex;
          align-items: center;
          text-decoration: none;
          color: #1a1a1a;
          font-weight: 700;
          font-size: 0.9rem;
          gap: 15px;
          transition: 0.3s;
        }

        .btn-icon {
          width: 35px;
          height: 35px;
          background: #f8f9fa;
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          transition: 0.3s;
        }

        .premium-btn:hover {
          color: #0d6efd;
          gap: 20px;
        }

        .premium-btn:hover .btn-icon {
          background: #0d6efd;
          color: white;
          transform: rotate(-45deg);
        }

        @media (max-width: 768px) {
          .main-title { font-size: 2.2rem; }
        }
      `}</style>
    </div>
  );
}

export default Services;
